from pathlib import Path

app_path=Path('app.js'); css_path=Path('styles.css'); rules_path=Path('PATIENT_CARE_RULES.md'); history_path=Path('docs/HISTORY.md')
app=app_path.read_text(encoding='utf-8'); css=css_path.read_text(encoding='utf-8'); rules=rules_path.read_text(encoding='utf-8'); history=history_path.read_text(encoding='utf-8')
start='// BEGIN VITAMIN D REFERENCE V2'
end='// END VITAMIN D REFERENCE V2'
if start in app:
    app=app[:app.index(start)]+app[app.index(end)+len(end):]
block=r'''// BEGIN VITAMIN D REFERENCE V2
const VITD_LOCAL_MAINTENANCE_V2={
  '600-daily':'600 IU once daily',
  '800-daily':'800 IU once daily',
  '1000-daily':'1,000 IU once daily',
  '50000-monthly':'50,000 IU once monthly'
};
function vitdReferencePlanV2(levelNg,age,weeklyDose,repeatMonths){
  const rda=Number(age)>70?800:600;
  if(levelNg<12)return {branch:'under12',label:'Below 12 ng/mL',weekly:8,weeklyDose:Number(weeklyDose)||50000,daily:800,repeatMonths:Number(repeatMonths)||3,summary:`${Number(weeklyDose||50000).toLocaleString()} IU once weekly for 8 weeks, then 800 IU once daily. Repeat 25(OH)D in ${Number(repeatMonths)||3} months.`};
  if(levelNg<20)return {branch:'12to20',label:'12 to <20 ng/mL',weekly:0,weeklyDose:0,daily:1000,repeatMonths:Number(repeatMonths)||3,summary:`1,000 IU once daily. Repeat 25(OH)D in ${Number(repeatMonths)||3} months.`};
  if(levelNg<=30)return {branch:'20to30',label:'20–30 ng/mL',weekly:0,weeklyDose:0,daily:800,repeatMonths:0,summary:'800 IU once daily.'};
  return {branch:'over30',label:'Above 30 ng/mL',weekly:0,weeklyDose:0,daily:rda,repeatMonths:0,summary:`No additional screening in this pathway. RDA: ${rda} IU once daily.`};
}
function renderVitaminDTool(){
  document.body.classList.add('physician-mode-active');document.body.classList.remove('vitd-patient-active');setActive('summary');
  const today=new Date().toISOString().slice(0,10);
  app.innerHTML=`<div class="screen physician-screen"><section class="vitd-builder"><a class="detail-back back-control dr" href="#/physician"><span class="back-control-icon" aria-hidden="true">←</span><span>Physician Mode</span></a><header><p class="eyebrow">PHYSICIAN MODE / VITAMIN D</p><h1>Choose a protocol</h1><p>Select the uploaded adult reference pathway or the customizable local clinic protocol. The clinician must review every instruction before export.</p></header><div class="vitd-protocol-cards"><button type="button" class="vitd-protocol-card selected" data-vitd-protocol-v2="reference"><small>ADULT REFERENCE PATHWAY</small><h2>Risk-factor and level algorithm</h2><p>Branches at &lt;12, 12–&lt;20, 20–30, and &gt;30 ng/mL.</p></button><button type="button" class="vitd-protocol-card" data-vitd-protocol-v2="local"><small>CUSTOMIZABLE</small><h2>Local clinic protocol</h2><p>Weekly 50,000 IU replacement, monthly phase, repeat level, and selected maintenance.</p></button></div><form id="vitd-builder-form-v2" data-vitd-mode="reference"><section id="vitd-risk-section"><fieldset class="vitd-safety compact"><legend>Risk factors for vitamin D deficiency</legend><label><input type="radio" name="vitd-risk-v2" value="yes" checked><span>Yes — limited sun exposure, osteoporosis, malabsorption or post-bariatric surgery, or medicine-related accelerated vitamin D metabolism</span></label><label><input type="radio" name="vitd-risk-v2" value="no"><span>No listed risk factors</span></label></fieldset></section><div class="vitd-form-grid"><label>25-hydroxyvitamin D level<input id="vitd-level-v2" type="number" min="1" max="300" step="0.1" required></label><label>Unit<select id="vitd-unit-v2"><option value="ng">ng/mL</option><option value="nmol">nmol/L</option></select></label><label>Patient age<input id="vitd-age-v2" type="number" min="18" max="120" value="50" required></label><label>First dose date<input id="vitd-start-v2" type="date" value="${today}" required></label><label id="vitd-reference-weekly-field">Weekly dose for &lt;12 ng/mL<select id="vitd-reference-weekly-dose"><option value="25000">25,000 IU</option><option value="50000" selected>50,000 IU</option></select></label><label id="vitd-reference-repeat-field">Reference repeat interval<select id="vitd-reference-repeat"><option value="3" selected>3 months</option><option value="4">4 months</option></select></label><label class="vitd-clinic-field">Clinic label (optional)<input id="vitd-clinic-v2" maxlength="80" placeholder="Clinic or service name"></label></div><section id="vitd-local-fields-v2" hidden><div class="vitd-form-grid"><label>Weekly phase duration<input id="vitd-local-weeks-v2" type="number" min="1" max="16" value="8"></label><label>Monthly phase duration<input id="vitd-local-months-v2" type="number" min="0" max="12" value="4"></label><label>Wait before repeat level<input id="vitd-local-wait-v2" type="number" min="0" max="6" value="1"></label><label>Maintenance after clinician review<select id="vitd-local-maintenance-v2"><option value="600-daily">600 IU daily</option><option value="800-daily" selected>800 IU daily</option><option value="1000-daily">1,000 IU daily</option><option value="50000-monthly">50,000 IU monthly</option></select></label></div></section><div id="vitd-protocol-preview-v2" class="vitd-protocol-preview"><strong>Enter the vitamin D level.</strong><span>The selected pathway will appear here.</span></div><fieldset class="vitd-safety"><legend>Required clinician confirmations</legend><label><input type="checkbox" required><span>This is an adult patient and the result is 25-hydroxyvitamin D in the selected unit.</span></label><label><input type="checkbox" required><span>I reviewed pregnancy, calcium status, kidney disease or stones, granulomatous disease, malabsorption or bariatric history, and interacting medicines.</span></label><label><input type="checkbox" required><span>I independently reviewed and selected this protocol. The app is generating a handoff, not prescribing autonomously.</span></label></fieldset><button class="btn dr vitd-generate" type="submit">Confirm and generate patient schedule</button></form><section id="vitd-export" class="vitd-export" hidden></section></section></div>`;
  updateVitdProtocolPreviewV2();
}
function vitdModeV2(){return document.getElementById('vitd-builder-form-v2')?.dataset.vitdMode||'reference'}
function updateVitdProtocolPreviewV2(){
  const target=document.getElementById('vitd-protocol-preview-v2');if(!target)return;
  const level=Number(document.getElementById('vitd-level-v2')?.value),unit=document.getElementById('vitd-unit-v2')?.value||'ng',mode=vitdModeV2();
  if(!level){target.innerHTML='<strong>Enter the vitamin D level.</strong><span>The selected pathway will appear here.</span>';return}
  const ng=unit==='nmol'?level/2.5:level;
  if(mode==='reference'){
    const risk=document.querySelector('input[name="vitd-risk-v2"]:checked')?.value||'yes',age=Number(document.getElementById('vitd-age-v2')?.value)||50;
    if(risk==='no'){const rda=age>70?800:600;target.innerHTML=`<strong>No listed risk factors</strong><span>Additional screening is not necessary in the uploaded pathway. RDA: ${rda} IU daily; supplement only when diet is insufficient.</span>`;return}
    const plan=vitdReferencePlanV2(ng,age,document.getElementById('vitd-reference-weekly-dose')?.value,document.getElementById('vitd-reference-repeat')?.value);target.innerHTML=`<strong>${plan.label}</strong><span>${plan.summary}</span>`;return;
  }
  const p=vitdProtocol(ng);if(!p){target.classList.add('out-of-range');target.innerHTML='<strong>Outside the local pathways.</strong><span>Use the reference pathway or a custom clinician plan.</span>';return}
  target.classList.remove('out-of-range');document.getElementById('vitd-local-weeks-v2').value=p.weekly;target.innerHTML=`<strong>${p.label} local pathway</strong><span>50,000 IU weekly for ${document.getElementById('vitd-local-weeks-v2').value} weeks, then 50,000 IU monthly for ${document.getElementById('vitd-local-months-v2').value} months, wait ${document.getElementById('vitd-local-wait-v2').value} month(s), repeat level, then ${VITD_LOCAL_MAINTENANCE_V2[document.getElementById('vitd-local-maintenance-v2').value]} after clinician confirmation.</span>`;
}
function vitdScheduleFromV2(){
  const mode=vitdModeV2(),level=Number(document.getElementById('vitd-level-v2').value),unit=document.getElementById('vitd-unit-v2').value,ng=unit==='nmol'?level/2.5:level,start=document.getElementById('vitd-start-v2').value,clinic=document.getElementById('vitd-clinic-v2').value.trim().slice(0,80),age=Number(document.getElementById('vitd-age-v2').value),risk=document.querySelector('input[name="vitd-risk-v2"]:checked')?.value||'yes';
  if(mode==='reference'){
    const plan=risk==='no'?{branch:'no-risk',label:'No listed risk factors',weekly:0,weeklyDose:0,daily:age>70?800:600,repeatMonths:0,summary:`RDA ${age>70?800:600} IU daily; supplementation only when dietary intake is insufficient.`}:vitdReferencePlanV2(ng,age,document.getElementById('vitd-reference-weekly-dose').value,document.getElementById('vitd-reference-repeat').value);
    const repeat=plan.repeatMonths?vitdIso(vitdAddMonths(start,plan.repeatMonths)):'';return {v:2,kind:'reference',p:plan.branch,pl:plan.label,s:start,w:plan.weekly,wd:plan.weeklyDose,d:plan.daily,r:repeat,summary:plan.summary,c:clinic};
  }
  const p=vitdProtocol(ng);if(!p)return null;const weeks=Number(document.getElementById('vitd-local-weeks-v2').value),months=Number(document.getElementById('vitd-local-months-v2').value),wait=Number(document.getElementById('vitd-local-wait-v2').value),maintenance=document.getElementById('vitd-local-maintenance-v2').value;const weekly=Array.from({length:weeks},(_,i)=>vitdIso(vitdAddDays(start,i*7))),firstMonthly=vitdAddMonths(weekly.at(-1),1),monthly=Array.from({length:months},(_,i)=>vitdIso(vitdAddMonths(firstMonthly,i))),repeat=vitdIso(vitdAddMonths(monthly.length?monthly.at(-1):weekly.at(-1),wait));return {v:2,kind:'local',p:p.id,s:start,w:weeks,m:months,r:repeat,mt:maintenance,c:clinic};
}
function vitdDatesV2(schedule){if(schedule.kind==='reference'){const weekly=Array.from({length:Number(schedule.w)||0},(_,i)=>vitdIso(vitdAddDays(schedule.s,i*7)));return {weekly,monthly:[],repeat:schedule.r||''}}return vitdExpandSchedule(schedule)}
function renderVitdExport(schedule){
  const target=document.getElementById('vitd-export');if(!target)return;const dates=vitdDatesV2(schedule),url=vitdPatientUrl(schedule);target.hidden=false;
  const summary=schedule.kind==='reference'?`<article><small>Reference branch</small><strong>${esc(schedule.pl)}</strong><span>${esc(schedule.summary)}</span></article><article><small>Daily plan</small><strong>${schedule.d?Number(schedule.d).toLocaleString()+' IU daily':'None'}</strong><span>${schedule.r?'Repeat level '+vitdPretty(schedule.r):'No repeat date generated'}</span></article>`:`<article><small>Weekly phase</small><strong>${schedule.w} doses</strong><span>${vitdPretty(dates.weekly[0])} – ${vitdPretty(dates.weekly.at(-1))}</span></article><article><small>Monthly phase</small><strong>${schedule.m} doses</strong><span>${dates.monthly.length?vitdPretty(dates.monthly[0])+' – '+vitdPretty(dates.monthly.at(-1)):'None'}</span></article><article><small>Maintenance after review</small><strong>${esc(VITD_LOCAL_MAINTENANCE_V2[schedule.mt])}</strong><span>Repeat level ${vitdPretty(dates.repeat)}</span></article>`;
  target.innerHTML=`<div class="vitd-export-head"><div><p class="eyebrow">PATIENT HANDOFF</p><h2>Vitamin D Journey is ready</h2><p>Review the protocol, dose, frequency, and dates before handoff.</p></div><div id="vitd-qr" class="vitd-qr"></div></div><div class="vitd-export-summary">${summary}</div><label class="vitd-link-label">Patient link<input id="vitd-patient-link" readonly value="${esc(url)}"></label><div class="vitd-export-actions"><button class="btn dr" data-vitd-open-patient="1">Open patient page</button><button class="btn ghost" data-vitd-copy-link="1">Copy link</button><button class="btn ghost" data-vitd-share-link="1">Share</button></div><aside class="vitd-export-note">Anyone with this link can open the schedule. Do not include patient-identifying information.</aside>`;target.dataset.schedule=vitdEncode(schedule);try{const qr=qrcode(0,'M');qr.addData(url);qr.make();document.getElementById('vitd-qr').innerHTML=qr.createSvgTag({cellSize:5,margin:4,scalable:true})}catch(e){document.getElementById('vitd-qr').textContent='Use the patient link.'}target.scrollIntoView({behavior:'smooth',block:'start'});
}
function renderVitaminDPatient(code){
  const schedule=vitdDecode(code);document.body.classList.add('vitd-patient-active');document.body.classList.remove('physician-mode-active','shine-intro-active','heal-intro-active','dr-intro-active');if(!schedule||![1,2].includes(schedule.v)){app.innerHTML='<div class="screen"><section class="detail"><h1>This schedule link is invalid</h1><p>Ask the clinic to generate a new link.</p></section></div>';return}
  if(schedule.v===1)return renderVitaminDPatientLegacyV2(code,schedule);
  const dates=vitdDatesV2(schedule),done=new Set(vitdLoadProgress(code)),weekly=dates.weekly||[],completed=weekly.filter((_,i)=>done.has('w'+i)).length;const protocolTitle=schedule.kind==='reference'?'Adult reference pathway':'Local clinic protocol';
  app.innerHTML=`<div class="vitd-patient-page"><header class="vitd-journey-hero"><div class="vitd-sun" aria-hidden="true"><span>☀</span></div><p class="eyebrow">YOUR VITAMIN D JOURNEY</p><h1>${esc(protocolTitle)}</h1><p>${schedule.c?esc(schedule.c)+' prepared this schedule. ':''}Follow only the dose and frequency shown.</p>${weekly.length?`<div class="vitd-progress"><div><span style="width:${Math.round(completed/weekly.length*100)}%"></span></div><strong>${completed} of ${weekly.length} weekly doses completed</strong></div>`:''}</header><main class="vitd-journey-main">${weekly.length?`<section class="vitd-phase"><div class="vitd-phase-head"><span>1</span><div><small>WEEKLY PHASE</small><h2>${Number(schedule.wd||50000).toLocaleString()} IU once weekly</h2></div></div><div class="vitd-dose-list">${weekly.map((d,i)=>`<label class="vitd-dose-card ${done.has('w'+i)?'done':''}"><input type="checkbox" data-vitd-dose="w${i}" ${done.has('w'+i)?'checked':''}><span class="vitd-dose-check">${done.has('w'+i)?'✓':''}</span><span><small>Weekly dose ${i+1}</small><strong>${vitdPretty(d)}</strong><em>${Number(schedule.wd||50000).toLocaleString()} IU · once weekly</em></span></label>`).join('')}</div></section>`:''}<section class="vitd-maintenance"><small>${schedule.kind==='local'?'MAINTENANCE AFTER CLINICIAN REVIEW':'DAILY PLAN'}</small><h2>${schedule.kind==='local'?esc(VITD_LOCAL_MAINTENANCE_V2[schedule.mt]):Number(schedule.d).toLocaleString()+' IU once daily'}</h2><p>${schedule.kind==='local'?'Start only after the repeat result is reviewed and the clinician confirms the plan.':esc(schedule.summary)}</p></section>${schedule.kind==='local'&&dates.monthly.length?`<section class="vitd-phase monthly"><div class="vitd-phase-head"><span>2</span><div><small>MONTHLY PHASE</small><h2>50,000 IU once monthly</h2></div></div><div class="vitd-dose-list">${dates.monthly.map((d,i)=>`<div class="vitd-dose-card"><span class="vitd-dose-check">${i+1}</span><span><small>Monthly dose ${i+1}</small><strong>${vitdPretty(d)}</strong><em>50,000 IU · once monthly</em></span></div>`).join('')}</div></section>`:''}${dates.repeat?`<section class="vitd-repeat"><span aria-hidden="true">🧪</span><div><small>REPEAT VITAMIN D LEVEL</small><h2>${vitdPretty(dates.repeat)}</h2></div></section>`:''}<section class="vitd-save-card"><h2>Save this journey to your phone</h2><div class="vitd-save-actions"><button class="btn dr" data-vitd-share-patient="1">Share or save link</button><button class="btn ghost" data-vitd-calendar="1">Add dates to calendar</button><button class="btn ghost" data-vitd-copy-patient="1">Copy link</button></div><details><summary>Add to your Home Screen</summary><div class="vitd-home-help"><p><strong>iPhone:</strong> open in Safari, tap Share, then Add to Home Screen.</p><p><strong>Android:</strong> open in Chrome, tap the menu, then Add to Home screen or Install app.</p></div></details></section><aside class="vitd-patient-safety"><strong>Use only this confirmed schedule.</strong><p>Do not take a high-dose product more often than shown. Contact the clinic if the strength differs, a dose was taken incorrectly, or the medical plan changes.</p></aside></main></div>`;app.dataset.vitdCode=code;app.dataset.vitdSchedule=vitdEncode(schedule);
}
const renderVitaminDPatientLegacyV2=(code,schedule)=>{schedule.v=1;const dates=vitdExpandSchedule(schedule),doses=[...dates.weekly.map((date,i)=>({id:'w'+i,date})),...dates.monthly.map((date,i)=>({id:'m'+i,date}))],done=new Set(vitdLoadProgress(code));app.innerHTML=`<div class="vitd-patient-page"><header class="vitd-journey-hero"><p class="eyebrow">YOUR VITAMIN D JOURNEY</p><h1>Local clinic protocol</h1></header><main class="vitd-journey-main"><div class="vitd-dose-list">${doses.map((x,i)=>`<label class="vitd-dose-card ${done.has(x.id)?'done':''}"><input type="checkbox" data-vitd-dose="${x.id}" ${done.has(x.id)?'checked':''}><span class="vitd-dose-check">${done.has(x.id)?'✓':''}</span><span><small>Dose ${i+1}</small><strong>${vitdPretty(x.date)}</strong><em>50,000 IU</em></span></label>`).join('')}</div></main></div>`;app.dataset.vitdCode=code;app.dataset.vitdSchedule=vitdEncode(schedule)};
document.addEventListener('click',e=>{const card=e.target.closest('[data-vitd-protocol-v2]');if(!card)return;const form=document.getElementById('vitd-builder-form-v2');if(!form)return;form.dataset.vitdMode=card.dataset.vitdProtocolV2;document.querySelectorAll('[data-vitd-protocol-v2]').forEach(x=>x.classList.toggle('selected',x===card));document.getElementById('vitd-risk-section').hidden=form.dataset.vitdMode!=='reference';document.getElementById('vitd-reference-weekly-field').hidden=form.dataset.vitdMode!=='reference';document.getElementById('vitd-reference-repeat-field').hidden=form.dataset.vitdMode!=='reference';document.getElementById('vitd-local-fields-v2').hidden=form.dataset.vitdMode!=='local';updateVitdProtocolPreviewV2()});
for(const name of ['input','change'])document.addEventListener(name,e=>{if(e.target?.closest('#vitd-builder-form-v2'))updateVitdProtocolPreviewV2()});
document.addEventListener('submit',e=>{if(e.target?.id!=='vitd-builder-form-v2')return;e.preventDefault();const schedule=vitdScheduleFromV2();if(!schedule){alert('This level is outside the local clinic pathways. Choose the reference pathway or a custom plan.');return}renderVitdExport(schedule)});
// END VITAMIN D REFERENCE V2
'''
app += '\n\n'+block+'\n'
css += r'''

/* VITAMIN D REFERENCE V2 */
.vitd-protocol-cards{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:14px;margin:20px 0}.vitd-protocol-card{text-align:left;border:2px solid #d9e2ec;border-radius:18px;background:#fff;padding:18px;min-height:150px;cursor:pointer}.vitd-protocol-card.selected{border-color:#2374b9;box-shadow:0 0 0 3px rgba(35,116,185,.12)}.vitd-protocol-card small{font-weight:800;letter-spacing:.08em;color:#46657d}.vitd-protocol-card h2{margin:7px 0}.vitd-safety.compact{margin:12px 0 18px}@media(max-width:680px){.vitd-protocol-cards{grid-template-columns:1fr}.vitd-protocol-card{min-height:0}}
'''
if 'uploaded adult vitamin D reference pathway' not in rules:
    rules += '\n\nThe approved Physician Mode exception also includes the uploaded adult vitamin D reference pathway with risk-factor screening and branches at below 12, 12 to below 20, 20 to 30, and above 30 ng/mL. The local clinic protocol may offer clinician-selected maintenance of 600 IU daily, 800 IU daily, 1,000 IU daily, or 50,000 IU monthly.\n'
history += '\n- Replaced the prior Endocrine Society reference card with the uploaded adult vitamin D risk-factor and level algorithm. Added local maintenance choices of 600 IU daily, 800 IU daily, 1,000 IU daily, or 50,000 IU monthly.\n'
app_path.write_text(app,encoding='utf-8');css_path.write_text(css,encoding='utf-8');rules_path.write_text(rules,encoding='utf-8');history_path.write_text(history,encoding='utf-8')
